// 203_SOLAR_BACKUP_DIMENSIONAMENTO_BATERIAS
const energia_critica_kwh = $input.item.json.energia_critica_kwh || 0;
const eficiencia_sistema = 0.85; // Padrão
const profundidade_descarga = 0.90; // Exemplo DoD LiFePO4
const margem_tecnica = 1.25; // 25% margem

const bateria_nominal_kwh = (energia_critica_kwh / eficiencia_sistema / profundidade_descarga) * margem_tecnica;

$input.item.json.bateria_nominal_kwh = parseFloat(bateria_nominal_kwh.toFixed(2));
$input.item.json.baterias_sugeridas = Math.ceil(bateria_nominal_kwh / 5.12); // Exemplo modulos 5.12kWh

return $input.item;
